// Simple Graphics Pipeline - Four Major Tasks
// ============================================

// Task 1: MODELING - Create geometric representation
// Represent a triangle as vertices in model space
function createTriangleModel():
 vertexBuffer = [
 {x: 0.0, y: 1.0, z: 0.0}, // top vertex
 {x: -1.0, y: -1.0, z: 0.0}, // bottom-left
 {x: 1.0, y: -1.0, z: 0.0} // bottom-right
 ]
 return vertexBuffer

// Task 2: GEOMETRIC PROCESSING
// Apply transformations, clipping, and projection
function geometricProcessing(vertices, modelMatrix, viewMatrix, projMatrix):
 transformedVertices = []

 // Step 2a: Model Transform (World Transform)
 for each v in vertices:
 worldPos = multiplyMatrixVector(modelMatrix, v)
 transformedVertices.append(worldPos)

 // Step 2b: View Transform
 viewVertices = []
 for each v in transformedVertices:
 viewPos = multiplyMatrixVector(viewMatrix, v)
 viewVertices.append(viewPos)

 // Step 2c: Projection Transform
 clipVertices = []
 for each v in viewVertices:
 projPos = multiplyMatrixVector(projMatrix, v)
 clipVertices.append(projPos)

 // Step 2d: Clipping - Remove primitives outside view frustum
 clippedVertices = clipAgainstFrustum(clipVertices)

 // Step 2e: Perspective Division (to NDC)
 ndcVertices = []
 for each v in clippedVertices:
 ndcPos = {x: v.x/v.w, y: v.y/v.w, z: v.z/v.w}
 ndcVertices.append(ndcPos)

 // Step 2f: Viewport Transform
 screenVertices = []
 for each v in ndcVertices:
 screenPos = {
 x: (v.x + 1) * width/2 + offsetX,
 y: (1 - v.y) * height/2 + offsetY, // flip Y
 z: v.z
 }
 screenVertices.append(screenPos)

 return screenVertices

// Task 3: RASTERIZATION - Convert primitives to fragments
function rasterizeTriangle(vertices):
 fragments = []

 // Step 3a: Edge Function for triangle coverage
 // Determine if pixel is inside triangle
 for each pixel (x, y) in boundingBox(vertices):
 bary = computeBarycentricCoords(vertices, x, y)

 if barycentricTest(bary):
 // Step 3b: Interpolate attributes (depth, color, UVs)
 z = interpolate(bary, v0.z, v1.z, v2.z)
 color = interpolate(bary, v0.color, v1.color, v2.color)
 uv = interpolate(bary, v0.uv, v1.uv, v2.uv)

 fragment = {
 x: x, y: y, z: z,
 color: color, uv: uv
 }
 fragments.append(fragment)

 return fragments

// Task 4: FRAGMENT PROCESSING - Texturing, blending, framebuffer
function fragmentProcessing(fragments, texture, depthBuffer, colorBuffer):
 for each frag in fragments:
 // Step 4a: Depth Test
 if frag.z < depthBuffer[frag.x, frag.y]:
 // Step 4b: Texture Sampling
 texColor = sampleTexture(texture, frag.uv)

 // Step 4c: Lighting Calculation
 litColor = computeLighting(frag.color, texColor)

 // Step 4d: Blending (if needed)
 finalColor = blendFragment(litColor, colorBuffer[frag.x, frag.y])

 // Step 4e: Write to framebuffer
 colorBuffer[frag.x, frag.y] = finalColor
 depthBuffer[frag.x, frag.y] = frag.z

// Main Pipeline Execution
function main():
 // Task 1: Modeling
 vertices = createTriangleModel()

 // Task 2: Geometric Processing
 screenVerts = geometricProcessing(
 vertices,
 identityMatrix, // model
 lookAtMatrix, // view
 perspectiveMatrix // projection
 )

 // Task 3: Rasterization
 fragments = rasterizeTriangle(screenVerts)

 // Task 4: Fragment Processing
 fragmentProcessing(fragments, texture, depthBuffer, colorBuffer)

// Scan Line Rasterization Algorithm
// =====================================
// Task 3: Rasterization - filling triangle using horizontal scan lines

// Structure definitions
struct Point:
 x, y, z
 r, g, b
 u, v

struct Edge:
 yMin, yMax // scan line range
 xAtYMin // starting x position
 inverseSlope // 1/m for x interpolation

// Main scanline rasterization function
function scanlineRasterizeTriangle(v0, v1, v2, frameBuffer):
 // Step 1: Sort vertices by Y coordinate (bottom to top)
 sorted = sortByY([v0, v1, v2])

 bottom = sorted[0] // lowest Y
 middle = sorted[1] // middle Y
 top = sorted[2] // highest Y

 // Step 2: Create edges
 edges = [
 createEdge(bottom, top), // left edge (long edge)
 createEdge(bottom, middle), // bottom short edge
 createEdge(middle, top) // top short edge
 ]

 // Step 3: Process each scan line
 for y from ceil(bottom.y) to floor(top.y):
 // Find active edges for this scan line
 activeEdges = []
 for each edge in edges:
 if y >= edge.yMin and y < edge.yMax:
 activeEdges.append(edge)

 // Calculate x intersections for this scan line
 x1 = calculateXAtY(activeEdges[0], y)
 x2 = calculateXAtY(activeEdges[1], y)

 // Ensure x1 <= x2 (left to right)
 if x1 > x2:
 swap(x1, x2)

 // Step 4: Fill pixels between x1 and x2
 for x from ceil(x1) to floor(x2):
 // Interpolate all attributes (z, color, uv) at this pixel
 // Using linear interpolation based on position in triangle

 t = (x - x1) / (x2 - x1) // parameter along scan line

 // Interpolate depth (for z-buffer)
 z = interpolateZ(v0, v1, v2, x, y)

 // Interpolate color (Gouraud shading)
 r = interpolateColor(v0.r, v1.r, v2.r, x, y)
 g = interpolateColor(v0.g, v1.g, v2.g, x, y)
 b = interpolateColor(v0.b, v1.b, v2.b, x, y)

 // Interpolate texture coordinates
 u = interpolateUV(v0.u, v1.u, v2.u, x, y)
 v = interpolateUV(v0.v, v1.v, v2.v, x, y)

 // Write fragment to framebuffer
 writePixel(frameBuffer, x, y, z, color(r,g,b), u, v)

// Helper: Create edge from two vertices
function createEdge(p1, p2):
 edge = new Edge
 edge.yMin = p1.y
 edge.yMax = p2.y

 // Calculate inverse slope (deltaX / deltaY)
 deltaY = p2.y - p1.y
 if deltaY != 0:
 edge.inverseSlope = (p2.x - p1.x) / deltaY
 edge.xAtYMin = p1.x
 else:
 edge.inverseSlope = 0
 edge.xAtYMin = p1.x

 return edge

// Helper: Calculate x position at given y using edge equation
function calculateXAtY(edge, y):
 deltaY = y - edge.yMin
 x = edge.xAtYMin + (edge.inverseSlope * deltaY)
 return x

// Helper: Interpolate z-coordinate using plane equation
function interpolateZ(v0, v1, v2, x, y):
 // Using barycentric coordinates approach
 area = edgeFunction(v0, v1, v2)
 w0 = edgeFunction(v1, v2, point(x,y)) / area
 w1 = edgeFunction(v2, v0, point(x,y)) / area
 w2 = edgeFunction(v0, v1, point(x,y)) / area

 return w0*v0.z + w1*v1.z + w2*v2.z

// Helper: Edge function for barycentric coordinates
function edgeFunction(a, b, c):
 return (c.x - a.x)*(b.y - a.y) - (c.y - a.y)*(b.x - a.x)

// Helper: Write pixel to framebuffer
function writePixel(buffer, x, y, z, color, u, v):
 // Store fragment data for next pipeline stage
 buffer[x,y] = Fragment(
 x: x, y: y,
 depth: z,
 color: color,
 texCoord: (u, v)
 )

// Example usage with sample triangle
function example():
 // Define triangle vertices with attributes
 v0 = Point(x: 50, y: 10, z: 0.5, r: 255, g: 0, b: 0, u: 0.0, v: 0.0)
 v1 = Point(x: 10, y: 90, z: 0.2, r: 0, g: 255, b: 0, u: 1.0, v: 0.0)
 v2 = Point(x: 90, y: 90, z: 0.8, r: 0, g: 0, b: 255, u: 0.5, v: 1.0)

 frameBuffer = createFrameBuffer(100, 100)

 // Perform scanline rasterization
 scanlineRasterizeTriangle(v0, v1, v2, frameBuffer)

 // Fragments now ready for Task 4: Fragment Processing
 return frameBuffer
